var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"뭐, 그림자라고 해도 이 정도인가? 별거 없군.","JPN":"なんだ、シャドウといってもこの程度か？　なんてことないな。","ENG":"So these were Shadows, huh? They weren’t so tough.","TWN":"什麼嘛，暗影就這點能耐嗎？沒什麼嘛？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 좀 조심해서 쓰라고 몇 번이나 말해?","JPN":"おい、もっと慎重に扱えって何度言やぁわかるんだ？","ENG":"Hey, how many times do I have to tell you to be careful when using this?","TWN":"喂，不是叫你用的時候小心一點嗎？到底要我說幾次？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"젠장, 벌써 고정장치가 헐거워졌잖아. 이러면 역류된 에너지가 죄다 새어 나온다고.","JPN":"くそ、もう固定装置がゆるくなっていやがる。こうなると逆流したエネルギーが全部漏れ出すんだ。","ENG":"Damn it, the clamps have already become too loose. At this point, the energy flowing backwards will start pouring out.","TWN":"該死的，固定裝置都鬆動了，這樣逆流的電力會全部漏出來啦！"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"무기라는 건 신뢰성이 중요한 거야. 험하게 써도 괜찮도록 만들어야지.","JPN":"武器なんてもんは信頼性が重要なんだ。乱暴に扱っても大丈夫なように作らなきゃ。","ENG":"Reliability is the most important factor for weapons. They should be built to last, no matter how roughly they’ve been used.","TWN":"武器最重要的就是可靠性，應該要做到怎麼使用都不會壞吧！"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"난 용병이지 수리기사가 아냐. 그런 건 저쪽 핑크머리 아가씨에게 이야기해.","JPN":"俺は傭兵であって修理士じゃない。そういうことはそっちのピンク頭の嬢ちゃんに言ってくれ。","ENG":"I’m a mercenary, not a repairman. Go speak with the pink-haired girl over there.","TWN":"我只是個傭兵，不是維修師傅，這些話你自己去跟粉紅頭小姐說吧！"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"덕분에 한숨 돌렸어요.","JPN":"おかげで一息つけました。","ENG":"We can take a breather now, thanks to you.","TWN":"多虧有你們才能稍微鬆口氣。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 어떻게 코핀 함보다 더 일찍 여기에 도착한 거죠?","JPN":"ところで、どうやってコフィン艦よりも早くここに到着できたんですか？","ENG":"But how were you able to arrive here faster than Coffin?","TWN":"不過你們怎麼比科芬艦還早到？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"말도 마, 이쪽도 난리였어.","JPN":"それね。こっちもしっちゃかめっちゃかだったわ。","ENG":"Don’t get me started, it was a total mess for us too.","TWN":"別提啦，我們這邊也是一團亂。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"갑자기 우리가 반역자로 몰리질 않나, 쿠데타가 벌어지질 않나…….","JPN":"突然アタシたちが反逆者として追い込まれたり、クーデターが起きたり……","ENG":"First we were branded traitors, then a coup broke out...","TWN":"一下說我們是叛國賊，一下又搞什麼政變……"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그쪽에서 보내 준 공간 좌표 계산 전문가가 아니었으면 애초에 도착하지도 못했을 거야.","JPN":"そちらから派遣してくれた、空間座標の計算士でなかったらそもそも到着できたかも怪しいわね。","ENG":"If it weren’t for the space coordinates calculation expert that you sent to us, we wouldn’t have been able to arrive here in the first place.","TWN":"要不是有你們派來的空間座標計算專家，我們根本不可能抵達這裡。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"공간 좌표 계산 전문가? 우리 회사에 그런 사람이 있었어요?","JPN":"空間座標の計算士？　うちの会社にそんな人いましたか？","ENG":"Space coordinates calculation expert? Was there anybody like that at our company?","TWN":"空間座標計算專家？我們公司有這種人嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"오, 얼터그레시브 실험체로군. 오랜만이다.","JPN":"お、オルタグレッシヴ実験体ではないか。久しぶりだな。","ENG":"Oh, it’s you, the Altergressive subject. Long time no see.","TWN":"喔，原來是替代進化體，好久不見。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"혹시 괜찮다면 너도 우리 다-크 세븐에 가입하지 않겠나?","JPN":"よかったらあなたもダーークセブンに入らないか？","ENG":"How would you like to join Daark Seven?","TWN":"可以的話，不如你也加入我們Dark 7的行列吧？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"밥도 맛있고 잠도 마음대로 잘 수 있다.","JPN":"食事もおいしく、寝るのも自由だ。","ENG":"The food is good and you get to sleep as much as you want.","TWN":"這邊伙食不錯，而且想睡就睡，完全沒問題。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"거기다 지금 가입한다면 넘버 6의 자리를 가져갈 수 있지.","JPN":"それに今入ればナンバー6の座を手に入れられる。","ENG":"Also, if you join now, you can take the position of Number 6.","TWN":"你現在加入的話，6號就歸你囉。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……그 이름을 알다니 역시 리플레이서 관계자인가?","JPN":"……その名前を知っているってことは、やはりリプレイサーの関係者？","ENG":"...Seeing that you know that name, you must be connected to the Replacers.","TWN":"……你竟然知道這個名字，你也跟克隆集團有關係嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이런 일을 할 사람은 역시 사장님뿐인데…….","JPN":"こんな事をする人は社長しかいないけれど……","ENG":"The only person who would do something like this is the Boss...","TWN":"果然，會做這種事的只有老闆……"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};